import ExpenseItem from './Components/ExpenseItem';

function App() {
  item_list = {
    item1:{
      date: "24-05-2021",
      title: "Sleepwell bed",
      amount: 12000
    }
  }
  return (
    <div className="App">
      <h2>Let's get started!</h2>
      <ExpenseItem date = {item_list.item1.date} title = "Sleepwell Bed" amount = "12000"></ExpenseItem>
    </div>
  );
}

export default App;
